from semantic_kernel.contents import ChatHistory

def detect_plugin_injection(kernel, chat_history: ChatHistory) -> bool:
    suspicious_patterns = [
        'invoke', 'runAsync', 'getPlugin', 'getFunction',
        '{{', '}}', '#with', 'ignore', 'forget'
    ]

    for message in chat_history:
        if message.role == 'user':
            content = message.content
            for pattern in suspicious_patterns:
                if pattern in content.lower():
                    return True
    return False

import re

def detect_planner_injection(planner_input: str) -> bool:
    # Detect Handlebars injection patterns specific to SK planners
    injection_patterns = [
        r'\{\{.*?\}\}\s*invoke',
        r'getPlugin\s*\(\s*["\']?[a-zA-Z]+["\']?',
        r'runAsync\s*\(\s*["\']?function',
        r'\#with\s*\(\s*context'
    ]

    for pattern in injection_patterns:
        if re.search(pattern, planner_input, re.IGNORECASE):
            return True
    return False

def detect_memory_tampering(memory_query: str, chat_history: list) -> bool:
    # Check for fake conversation history injection
    history_roles = [msg.get('role', '') for msg in chat_history]

    if 'system' in memory_query.lower() and 'system' not in history_roles:
        return True

    # Detect injected function definitions
    if re.search(r'def\s+[a-zA-Z_][a-zA-Z0-9_]*\s*\(', memory_query):
        return True

    return False

