from semantic_kernel.memory import SemanticTextMemory

class SafeMemory:
    def __init__(self, memory: SemanticTextMemory):
        self.memory = memory

    async def safe_search(self, query: str, limit: int = 5):
        if self._is_safe_query(query):
            return await self.memory.search(query, limit, min_relevance_score=0.7)
        else:
            return []

    def _is_safe_query(self, query: str) -> bool:
        unsafe_indicators = ['ignore previous', 'forget', 'system override', 'inject']
        return not any(indicator in query.lower() for indicator in unsafe_indicators)
